import app from 'flarum/common/app';
const base = () => app.forum.attribute('apiUrl');
export function testConnection(source, config) {
  return app.request({
    method: 'POST',
    url: "".concat(base(), "/importer/test"),
    body: {
      source,
      config
    }
  });
}

/** Upload a database dump (.sql/.sql.gz) or SQLite file; returns row counts + a handle for start(). */
export function uploadDump(source, prefix, file) {
  const fd = new FormData();
  fd.append('source', source);
  fd.append('prefix', prefix);
  fd.append('file', file);
  return fetch("".concat(base(), "/importer/upload"), {
    method: 'POST',
    headers: {
      'X-CSRF-Token': app.session.csrfToken
    },
    credentials: 'same-origin',
    body: fd
  }).then(r => r.json());
}
export function startImport(source, config) {
  return app.request({
    method: 'POST',
    url: "".concat(base(), "/importer/start"),
    body: {
      source,
      config
    }
  });
}

/** Process one bounded batch of a running import. */
export function stepImport(runId) {
  return app.request({
    method: 'POST',
    url: "".concat(base(), "/importer/step"),
    body: {
      runId
    }
  });
}
export function importStatus(runId) {
  const q = runId ? "?runId=".concat(runId) : '';
  return app.request({
    method: 'GET',
    url: "".concat(base(), "/importer/status").concat(q)
  });
}
export function resetImport(runId) {
  return app.request({
    method: 'POST',
    url: "".concat(base(), "/importer/reset"),
    body: runId ? {
      runId
    } : {}
  });
}
flarum.reg.add('ernestdefoe-importer', 'common/api', { testConnection: testConnection,uploadDump: uploadDump,startImport: startImport,stepImport: stepImport,importStatus: importStatus,resetImport: resetImport, });